export function getIndicesHub() {
  return {
    articles: INDICES_ARTICLES,
    lessons: INDICES_LESSONS,
    glossary: INDICES_GLOSSARY,
    strategies: INDICES_STRATEGIES,
    stats: {
      articlesCount: INDICES_ARTICLES.length,
      lessonsCount: INDICES_LESSONS.length,
      glossaryCount: INDICES_GLOSSARY.length,
      strategiesCount: INDICES_STRATEGIES.length,
    },
  };
}

export function getRelatedIndicesContent(slug: string, type: "article" | "lesson", limit = 3) {
  if (type === "article") {
    const article = INDICES_ARTICLES.find((a) => a.slug === slug);
    if (!article) return [];
    return INDICES_ARTICLES.filter((a) => a.slug !== slug && a.tags.some((t) => article.tags.includes(t))).slice(0, limit);
  }
  const lesson = INDICES_LESSONS.find((l) => l.id === slug);
  if (!lesson) return [];
  return INDICES_LESSONS.filter((l) => l.id !== slug && l.tags.some((t) => lesson.tags.includes(t))).slice(0, limit);
}
